import { diffLines, diffWords, diffChars } from 'diff';

/**
 * Apply text processing options
 * @param {string} text - Text to process
 * @param {import('../types.js').TextProcessingOptions} options - Processing options
 * @returns {string} Processed text
 */
export function processText(text, options = {}) {
  const { ignoreCase = false, ignoreWhitespace = false } = options;
  
  let processed = text;
  
  if (ignoreCase) {
    processed = processed.toLowerCase();
  }
  
  if (ignoreWhitespace) {
    processed = processed.replace(/\s+/g, ' ').trim();
  }
  
  return processed;
}

/**
 * Compare two texts and return differences
 * @param {string} text1 - First text content
 * @param {string} text2 - Second text content  
 * @param {import('../types.js').CompareOptions} [options] - Comparison options
 * @returns {import('../types.js').DiffResult} Comparison result
 */
export function compareTexts(text1, text2, options = {}) {
  const { ignoreWhitespace = false, ignoreCase = false, mode = 'char' } = options;
  
  try {
    const processedText1 = processText(text1, { ignoreCase, ignoreWhitespace });
    const processedText2 = processText(text2, { ignoreCase, ignoreWhitespace });
    
    // Choose diff function based on mode
    let changes;
    switch (mode) {
      case 'char':
        changes = diffChars(processedText1, processedText2);
        break;
      case 'word':
        changes = diffWords(processedText1, processedText2);
        break;
      case 'line':
        changes = diffLines(processedText1, processedText2);
        break;
      default:
        throw new Error(`Invalid diff mode: ${mode}. Must be 'char', 'word', or 'line'.`);
    }
    
    // Calculate summary statistics
    let added = 0;
    let removed = 0;
    
    changes.forEach(change => {
      if (change.added) {
        added += change.count || 1;
      } else if (change.removed) {
        removed += change.count || 1;
      }
    });
    
    const identical = changes.length === 0 || 
      (changes.length === 1 && !changes[0].added && !changes[0].removed);
    
    // Create mode-appropriate summary
    const unit = mode === 'char' ? 'characters' : mode === 'word' ? 'words' : 'lines';
    const summary = identical 
      ? 'PDFs are identical'
      : `${added} ${unit} added, ${removed} ${unit} removed`;
    
    return {
      changes,
      summary,
      identical
    };
  } catch (error) {
    throw new Error(`Failed to compare texts: ${error.message}`);
  }
}